import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const S=JSON.parse('{"title":"乌尔班巨炮","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/远程武器/5.S级/乌尔班巨炮.md","filePath":"4.资源分区/7.物品与装备/2.武器/远程武器/5.S级/乌尔班巨炮.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/远程武器/5.S级/乌尔班巨炮.md"};function p(_,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"乌尔班巨炮",tabindex:"-1"},[s("乌尔班巨炮 "),e("a",{class:"header-anchor",href:"#乌尔班巨炮","aria-label":'Permalink to "乌尔班巨炮"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：灵魂蓝调015")])])],-1),o('<h1 id="乌尔班巨炮-1" tabindex="-1">乌尔班巨炮 <a class="header-anchor" href="#乌尔班巨炮-1" aria-label="Permalink to &quot;乌尔班巨炮&quot;">​</a></h1><p>乌尔班巨炮<br> 价格：S+8000<br> 人类历史上最强的武器是乌尔班巨炮，因为1453年奥斯曼土耳其人使用乌尔班巨炮一炮轰飞了君士坦丁堡的城墙，与此同时君士坦丁堡的民众为君士坦丁十一世写了《你将如闪电般归来》。众所周知，闪电为光速，而根据相对论，物体只能无限趋近于光速，而已经过去整整571年了，君士坦丁十一世依旧没有如闪电般归来，说明乌尔班巨炮连着君士坦丁十一世一起轰飞了至少285.5光年远。因此人类历史上最强大的武器是乌尔班巨炮。</p><p>武器体积：13<br> 武器伤害：46L<br> 武器属性：【法破】【8加骰】【超级贯穿】<br> 额外特性：【攻城器械】【超级巨炮】【光速炮击】<br> 攻城器械：该武器的攻击命中10体积及以上的物体时，将正常结算造成的伤害，若攻击的目标小于5体积，则其在反射豁免检定时额外获得20点反射豁免上的环境加值，在这之间的部分则获得10点环境加值。</p><p>超级巨炮：该武器使用专属的【乌尔班巨炮】炮弹，在填装时会自动出现在你的手中，视为【无限炮弹】。<br> 此外，使用该炮弹的武器射程是3000米，不进行正常防御而是改为使对方进行反射豁免伤害，攻击成功数转变为5米的范围伤害。</p><p>光速炮击：在某个时空中，乌尔班巨炮将君士坦丁十一世轰出了超过285.5光年以上的距离，因此被这门大炮可以使命中的单位承受SSS级时空来源的即死效果，并且受到SSS级的禁止复活影响，除非目标能够以超光速跑回来。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const f=r(d,[["render",p]]);export{S as __pageData,f as default};
